/**
 * Unit tests for frustration-detector prompt hook
 * Issue #1243: DX observability — frustration signal detection
 *
 * v7.30.0: appendAnalytics removed — data flows via emit() to yonatan-hq (#1266)
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('../../lib/common.js', () => mockCommonBasic());

vi.mock('../../lib/analytics.js', () => ({
  appendAnalytics: vi.fn(),
  hashProject: vi.fn(() => 'proj_hash'),
  getTeamContext: vi.fn(() => ({})),
}));

import { detectFrustration, frustrationDetector } from '../../prompt/frustration-detector.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

function createInput(prompt: string, overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'UserPromptSubmit',
    tool_name: 'UserPromptSubmit',
    session_id: 'test-session',
    tool_input: {},
    prompt,
    ...overrides,
  };
}

let testCtx: ReturnType<typeof createTestContext>;
describe('prompt/frustration-detector', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.clearAllMocks();
  });

  // ===========================================================================
  // detectFrustration (pure function)
  // ===========================================================================

  describe('detectFrustration', () => {
    describe('detects frustration signals', () => {
      test.each([
        ['wtf is going on'],
        ['wth happened here'],
        ['ffs this is broken'],
        ['this is shitty code'],
        ['this is horrible'],
        ['this is awful'],
        ['I am pissed off'],
        ['what the fuck'],
        ['what the hell is this'],
        ['this is fucking broken'],
        ['so frustrating to debug'],
        ['this sucks'],
        ['damn it'],
      ])('detects: "%s"', (prompt) => {
        expect(detectFrustration(prompt)).toBe(true);
      });
    });

    describe('does NOT flag normal prompts', () => {
      test.each([
        ['implement user authentication'],
        ['fix the login bug'],
        ['what does this function do'],
        ['help me refactor this'],
        ['run the tests'],
        ['create a new component'],
        ['how does this work'],
        ['add error handling'],
        ['the dashboard is slow'],
        ['can you review this code'],
        [''],
      ])('does not flag: "%s"', (prompt) => {
        expect(detectFrustration(prompt)).toBe(false);
      });
    });

    describe('edge cases', () => {
      test('case insensitive', () => {
        expect(detectFrustration('WTF is this')).toBe(true);
        expect(detectFrustration('This SUCKS')).toBe(true);
      });

      test('does not match partial words', () => {
        // "shift" contains "shit" but should NOT match (word boundary)
        expect(detectFrustration('shift the data left')).toBe(false);
      });

      test('does not match "shitake" or similar', () => {
        expect(detectFrustration('add shitake mushrooms')).toBe(false);
      });

      test('does not match "awesome" despite containing "awful" substring', () => {
        expect(detectFrustration('this is awesome')).toBe(false);
      });
    });
  });

  // ===========================================================================
  // frustrationDetector (main hook, testCtx)
  // ===========================================================================

  describe('frustrationDetector', () => {
    describe('guard clauses', () => {
      test('skips empty prompts', () => {
        const result = frustrationDetector(createInput(''), testCtx);
        expect(result.continue).toBe(true);
        expect(result.suppressOutput).toBe(true);
      });

      test('skips very short prompts', () => {
        const result = frustrationDetector(createInput('hi'), testCtx);
        expect(result.continue).toBe(true);
      });

      test('skips slash commands', () => {
        const result = frustrationDetector(createInput('/ork:implement wtf'), testCtx);
        expect(result.continue).toBe(true);
      });
    });

    // v7.30.0: appendAnalytics removed — data flows via emit() to yonatan-hq (#1266)
    // Analytics logging tests removed; frustration signal is now emitted, not written to JSONL.

    describe('output behavior', () => {
      test('always returns silent success (analytics-only)', () => {
        const result = frustrationDetector(createInput('wtf happened'), testCtx);
        expect(result.continue).toBe(true);
        expect(result.suppressOutput).toBe(true);
        // Should NOT modify Claude's behavior
        expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
        expect(result.systemMessage).toBeUndefined();
      });

      test('never blocks execution', () => {
        const result = frustrationDetector(createInput('fucking broken useless shit'), testCtx);
        expect(result.continue).toBe(true);
      });
    });

    // v7.30.0: privacy tests for appendAnalytics payload removed (#1266)
    // Privacy is now enforced at the emit() layer in webhook-forwarder.

    describe('error resilience', () => {
      test('survives internal error gracefully', () => {
        // Hook should never crash the hook chain
        const result = frustrationDetector(createInput('wtf broke'), testCtx);
        expect(result.continue).toBe(true);
      });
    });
  });
});
